import torch
import triton
import triton.language as tl

@triton.jit
def mean_kernel(x_ptr, output_ptr, n_elements, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    block_start = pid * BLOCK_SIZE
    offsets = block_start + tl.arange(0, BLOCK_SIZE)
    mask = offsets < n_elements
    x = tl.load(x_ptr + offsets, mask=mask)
    # Compute mean for this block
    mean_val = tl.sum(x) / tl.cdiv(n_elements, BLOCK_SIZE)
    tl.store(output_ptr + pid, mean_val)

@triton.jit
def mean_kernel_2d(x_ptr, output_ptr, rows, cols, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    row = pid // cols
    col = pid % cols
    if row < rows and col < cols:
        x = tl.load(x_ptr + row * cols + col)
        mean_val = tl.sum(x) / cols
        tl.store(output_ptr + row, mean_val)

@triton.jit
def mean_kernel_2d_keepdim(x_ptr, output_ptr, rows, cols, BLOCK_SIZE: tl.constexpr):
    pid = tl.program_id(0)
    row = pid
    if row < rows:
        x = tl.load(x_ptr + row * cols, mask=tl.arange(0, cols) < cols)
        mean_val = tl.sum(x) / cols
        tl.store(output_ptr + row, mean_val)


def mean_triton(input, dim, keepdim=False, dtype=None, out=None):
    if dtype is not None:
        input = input.to(dtype)

    if isinstance(dim, int):
        dim = (dim,)

    # Handle negative dimensions
    dim = tuple(d if d >= 0 else input.dim() + d for d in dim)

    # Validate dimensions
    for d in dim:
        if d < 0 or d >= input.dim():
            raise ValueError(f"Dimension {d} is out of range for tensor with {input.dim()} dimensions")

    # Create output shape
    output_shape = list(input.shape)
    for d in sorted(dim, reverse=True):
        if keepdim:
            output_shape[d] = 1
        else:
            output_shape.pop(d)

    if not output_shape:
        output_shape = [1]

    output = torch.empty(output_shape, dtype=input.dtype, device=input.device)

    if len(dim) == 1 and dim[0] == 0:
        # Reduce along first dimension
        if keepdim:
            output = torch.empty(input.shape[0], 1, dtype=input.dtype, device=input.device)
            grid = (input.shape[0],)
            mean_kernel_2d_keepdim[grid](input, output, input.shape[0], input.shape[1], BLOCK_SIZE=1024)
        else:
            output = torch.empty(input.shape[0], dtype=input.dtype, device=input.device)
            grid = (input.shape[0],)
            mean_kernel_2d[grid](input, output, input.shape[0], input.shape[1], BLOCK_SIZE=1024)
    else:
        # General case
        total_elements = input.numel()
        grid = (triton.cdiv(total_elements, 1024),)
        mean_kernel[grid](input, output, total_elements, BLOCK_SIZE=1024)

    return output
